function promptRules(category:string){
  const rules:Record<string,string[]>={
    Research:["Utamakan sumber primer dan cantumkan tanggal data.","Pisahkan fakta, inferensi, opini, dan ketidakpastian.","Jangan menutup gap riset dengan tebakan."],
    Writing:["Jelaskan audience, tone, channel, dan struktur yang diinginkan.","Pertahankan fakta inti dan tandai klaim yang perlu bukti.","Hindari kalimat korporat yang terlalu generik."],
    Coding:["Sebutkan stack, environment, error, langkah reproduksi, dan batas perubahan.","Minta perubahan kecil dengan test atau cara verifikasi.","Jangan mengubah bagian yang tidak terkait masalah."],
    Automation:["Tulis trigger, input schema, action, condition, approval, log, dan fallback.","Pisahkan langkah otomatis dari langkah yang butuh manusia.","Uji data kosong, duplikat, timeout, dan permission."],
    Learning:["Sebutkan level awal, tujuan belajar, contoh yang dekat, dan cara cek pemahaman.","Minta penjelasan bertahap sebelum latihan.","Tutup dengan satu pertanyaan refleksi atau latihan kecil."],
    Marketing:["Masukkan persona, offer, channel, metric, dan klaim yang boleh dipakai.","Pisahkan insight pelanggan dari asumsi.","Jangan membuat janji performa tanpa bukti."],
    "Web3 Research":["Gunakan sumber primer, timestamp, dan caveat risiko.","Pisahkan data on-chain, docs resmi, opini, dan narasi pasar.","Jangan memberi financial advice."],
    "Client Work":["Tulis scope, deliverable, acceptance criteria, out-of-scope, dan keputusan yang dibutuhkan.","Jangan menjanjikan hal di luar brief.","Buat output yang siap dibahas dengan klien."]
  };
  return rules[category] || ["Tulis input yang tersedia, batasan, format output, dan bagian yang perlu dicek manusia.","Pisahkan fakta, asumsi, dan risiko.","Jangan membuat data baru."];
}

export const expandedPrompts:DirectoryItem[]=Object.entries(promptGroups).flatMap(([category,specs])=>specs.map(([title,useCase,variables,instruction,output])=>({
  title,category,level:category==="Coding"||category==="Automation"||category==="Web3 Research"?"Menengah":"Pemula",tag:"Template",
  description:useCase,details:[`Use case: ${useCase}`,`Variabel: ${variables}`,`Output: ${output}`],
  action:`Tugas: ${instruction}\n\nInput yang harus tersedia: ${variables}.\n\nAturan kerja:\n${promptRules(category).map(rule=>`- ${rule}`).join("\n")}\n\nOutput yang diharapkan: ${output}.`,
  sections:[
    {title:"Dipakai buat apa",content:useCase},{title:"Yang perlu kamu isi",content:variables.split(", ")},
    {title:"Cara memakai",content:["Ganti semua teks dalam tanda kurung siku","Tambahkan contoh output atau batasan jika punya","Jalankan dengan satu input nyata","Review hasil memakai aturan kategori","Simpan versi yang sudah terbukti bekerja"]},
    {title:"Aturan kategori",content:promptRules(category)},
    {title:"Contoh input",content:`Topik/konteks: contoh nyata dari pekerjaanmu. Target pembaca: orang yang akan memakai hasilnya. Batasan: waktu, panjang, data, dan tone.`},
    {title:"Hasil yang diharapkan",content:output},{title:"Template prompt",content:instruction}
  ]
})));

