function completionCriteria(p:ProjectSpec){
  return [`Output final sudah berupa ${p.output}`,`Minimal satu input nyata diuji dari awal sampai akhir`,`Ada catatan revisi dari versi awal ke versi final`,`Project bisa dibuka, dites, atau ditunjukkan ke orang lain`];
}

function proofItems(p:ProjectSpec){
  return [p.portfolio,"Screenshot atau rekaman demo singkat","Contoh input dan output yang sudah aman untuk dibagikan","Checklist QA yang menunjukkan cara project diuji"];
}

function smallStart(p:ProjectSpec){
  return `Mulai dari satu alur utama dulu. Pakai satu contoh input nyata, hasilkan ${p.output}, lalu dokumentasikan batasannya sebelum menambah fitur.`;
}

