function proofRequired(m:MonetizeSpec){
  return [`Satu contoh output yang mirip dengan deliverable: ${m.deliverables[0]}`,m.portfolio,"Proses kerja singkat yang menunjukkan input, langkah, review, dan hasil","Batas layanan yang jelas agar klien tahu apa yang tidak termasuk"];
}

function realisticLimit(m:MonetizeSpec){
  return `${m.title} tidak otomatis menjamin hasil bisnis besar. Nilainya muncul kalau scope jelas, data klien cukup, output direview, dan maintenance disepakati sejak awal.`;
}

